/// Parse an instance event payload for MyCharacter from raw event hash and bytes.
pub fn parse_my_character_instance_event(event_hash: i32, payload_bytes: &[u8]) -> Result<MyCharacterInstanceEventPayload, deku::DekuError> {
    match MyCharacterInstanceEvent::from_hash(event_hash) {
        Some(event_type) => event_type.parse_payload(payload_bytes),
        None => Ok(MyCharacterInstanceEventPayload::Unknown {
            event_hash,
            payload: payload_bytes.to_vec(),
        }),
    }
}

